#include <bits/stdc++.h>
using namespace std;

int n,m,g[1<<12][1<<12],f[13][1<<12];

int main(){
    scanf("%d%d",&n,&m);
    memset(f,0x3f,sizeof(f));
    memset(g,0x3f,sizeof(g));
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[1<<u-1][1<<v-1]=g[1<<v-1][1<<u-1]=min(g[1<<u-1][1<<v-1],w);
    }
    for(int i=1;i<1<<n;i++){
        if(i==(i&(-i)))
            continue;
        for(int j=0;j<n;j++)
            g[i][1<<j]=min(g[i-(i&(-i))][1<<j],g[i&(-i)][1<<j]);
    }
    for(int i=1;i<1<<n;i++)
        for(int j=1;j<1<<n;j++)
            if(j!=(j&(-j)))
                g[i][j]=min(g[i][j],g[i][j&(-j)]+g[i][j-(j&(-j))]);
    for(int i=1;i<=n;i++)
        f[0][1<<i-1]=0;
    for(int i=1;i<=n;i++)
        for(int j=1;j<1<<n;j++)
            for(int k=((j-1)&j);k;k=((k-1)&j)){
                //printf("%d %d %d\n",j,k,f[i-1][k]+1LL*i*g[k][j-k]);
				f[i][j]=min(1LL*f[i][j],f[i-1][k]+1LL*i*g[k][j-k]);
            }
    int ans=0x3f3f3f3f;
    for(int i=0;i<=n;i++)
        ans=min(ans,f[i][(1<<n)-1]);
    printf("%d",ans);
    return 0;
}
